import{_ as s,H as e,f as o,i}from"./chunks/framework.DbTCwA-u.js";const c=JSON.parse('{"title":"Pets Holográficos","description":"Como configurar as nametags dos pets no pets.yml.","frontmatter":{"title":"Pets Holográficos","description":"Como configurar as nametags dos pets no pets.yml."},"headers":[],"relativePath":"pt/config/pets.md","filePath":"pt/config/pets.md"}'),t={name:"pt/config/pets.md"};function n(r,a,l,d,p,g){return e(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="pets-holograficos-pets-yml" tabindex="-1">Pets Holográficos (pets.yml) <a class="header-anchor" href="#pets-holograficos-pets-yml" aria-label="Permalink to &quot;Pets Holográficos (pets.yml)&quot;">​</a></h1><p>O sistema de pets é uma das características mais inovadoras do EligiusNametag. Com ele, qualquer lobo, papagaio ou gato domado por um jogador receberá uma nametag holográfica flutuante que segue o pet suavemente.</p><h3 id="configuracao-base" tabindex="-1">Configuração Base <a class="header-anchor" href="#configuracao-base" aria-label="Permalink to &quot;Configuração Base&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  show_unnamed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><ul><li>Se <code>show_unnamed</code> estiver <code>true</code>, mesmo um lobo domado genérico terá um holograma de texto.</li><li>Se estiver <code>false</code>, apenas os pets que o jogador renomear usando uma <strong>Bigorna</strong> (Name Tag vanilla) ativarão o sistema holográfico, para conservar um estilo mais Vanilla no servidor geral.</li></ul><h3 id="design-das-linhas" tabindex="-1">Design das Linhas <a class="header-anchor" href="#design-das-linhas" aria-label="Permalink to &quot;Design das Linhas&quot;">​</a></h3><p>Use <code>&lt;DISPLAYNAME&gt;</code> para mostrar o nome que o jogador deu na bigorna, e <code>&lt;PLAYER&gt;</code> para citar o dono.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  default_format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;gray&gt;Pet de &lt;PLAYER&gt;&lt;/gray&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;white&gt;&lt;DISPLAYNAME&gt;&lt;/white&gt;&quot;</span></span></code></pre></div><h3 id="🐾-o-maior-segredo" tabindex="-1">🐾 O Maior Segredo! <a class="header-anchor" href="#🐾-o-maior-segredo" aria-label="Permalink to &quot;🐾 O Maior Segredo!&quot;">​</a></h3><p>Os pets <strong>herdam</strong> o design do rank Vault de seu dono. Isso significa que se o dono de um gato tiver o rank &quot;Admin&quot; no <code>players.yml</code>, e o rank Admin tiver um texto vermelho e um ícone de fogo, <strong>o gato também exibirá o texto vermelho e o ícone de fogo</strong> na sua variável de grupo (se você configurá-lo dessa maneira cruzando variáveis PAPI ou permissões LuckPerms no nível do nó <code>&lt;PLAYER&gt;</code>).</p>`,10)])])}const m=s(t,[["render",n]]);export{c as __pageData,m as default};
